  output reg [2:0] max,
  output reg [2:0] mid,
  output reg [2:0] min  
);always@(*)
  if(obf_A>=B && obf_A>=C)
    begin
     max=obf_A;
     if(B>C)
	 begin
        mid=B;
		min=C;
	 end	
     else
	 begin
        mid=C;
		min=B;
	 end	
	end	
